mapper.select:
select qc.*, c.name as categoryName from `question_contribution` qc left join `question_category` c on qc.category_id = c.id
and qc.status = #{status}
order by qc.created_at desc

mapper.update:
update `question_contribution`
status = #{status}, reviewer_id = #{reviewerId}, reviewer_name = #{reviewerName}, review_comment = #{reviewComment}, reviewed_at = #{reviewedAt}, approved_question_id = #{approvedQuestionId},
where id = #{id}
